  'surfline': {
    id: 'surfline',
    type: 'brand',
    name: 'Surfline',
    sport: ['surf'],
    founded: '1985',
    headquarters: 'Huntington Beach, California',
    bio: "Surfline is the world's leading surf forecasting, media, and technology company, founded in 1985 as a pay-per-call telephone surf report service by Sean Collins, Jerry Arnold, and David Wilk. Collins' self-developed wave forecasting methodology — eventually formalized as the proprietary LOLA swell-modeling algorithm — revolutionized how surfers worldwide plan their sessions. Surfline moved online in 1995 as surfline.com, offering live webcams of surf breaks and premium forecast content. The company has been acquired and restructured multiple times and as of 2023 is led by CEO Ross Garrett. Surfline acquired Magicseaweed in 2019, absorbing that platform's global audience and talent including Ben Freeston (VP Product & Innovation). Surfline's editorial team, led by Editor in Chief Marcus Sanders, produces news, features, and the Surfing A-to-Z biographical encyclopedia. Its flagship video series Maps to Nowhere, produced with O'Neill and narrated by Matt Rode, documents exploration of remote breaks worldwide. The company also operates the Twenty Foot Plus big-wave platform with Jamie Mitchell, Kai Lenny, and Justine Dupont, and the Surfline Sessions data-capture product for surfers to review their own sessions.",
    connections: [
      { id: 'sean-collins', label: 'co-founder' },
      { id: 'matt-rode', label: 'Maps to Nowhere host' },
      { id: 'kai-lenny', label: 'Heavy Water Surf / Twenty Foot Plus' },
      { id: 'jamie-mitchell', label: 'Heavy Water Surf / Twenty Foot Plus' },
    ],
    source: "surfline.com; en.wikipedia.org/wiki/Surfline",
  },


