  'mimi-munro': {
    id: 'mimi-munro',
    type: 'athlete',
    name: 'Mimi Munro',
    sport: ['surf'],
    location: 'Ormond Beach, FL (Volusia County)',
    era: '1960s–present',
    bio: "Mimi Munro (born Daytona Beach, raised Ormond Beach) is one of the founding legends of East Coast women's surfing. She began surfing in 1962 and by age 12 was Florida State Champion (1964). She won the East Coast Championship in 1965 and 1966, then placed 3rd at the 1966 World Surfing Championships in San Diego — making her the first East Coaster to compete internationally at that level. She rode for Hobie Surfboards and was sponsored by the Daytona Beach Surf Shop. In 1967 she was inducted into the International Surfing Hall of Fame. She quit competitive surfing at 16, returned at approximately 38 years old, and was inducted into the East Coast Surf Legends Hall of Fame in 1996 as the first woman ever honored by that body. In 2007 she received the Surfing Walk of Fame Woman of the Year award. She still teaches surf camps in Ormond Beach.",
    connections: [
      { id: 'east-coast-surfing-hall-of-fame', label: 'Surf Legends Hall of Fame 1996 (first woman)' },
    ],
    source: "eastcoastsurfinghalloffame.org; Surfing Walk of Fame; Daytona Beach.com; SURFER Magazine",
  },

