  'bud-browne': {
    id: 'bud-browne',
    type: 'person',
    name: 'Bud Browne',
    sport: ['surf'],
    role: 'Pioneer Surf Filmmaker',
    era: '1950s–1960s',
    bio: "Bud Browne (1912–2008) is the father of surf cinema. A former competitive swimmer and surfer, he became the first person to shoot, edit, and tour surf films to paying audiences — pioneering the surf film format that Bruce Brown and Greg Noll would follow. His films include Hawaiian Surfriders (1953), Cat on a Hot Foam Board (1959), and many others that documented the Hawaiian surf scene before it reached the mainland. He traveled the world with his camera and projector, screening films to surf clubs. He is a founding figure of surf media.",
    connections: [
      { id: 'hawaiian-surfriders', label: 'Director (1953)' },
      { id: 'pipeline', label: 'Documented early Hawaiian surf' },
    ],
    source: "encyclopediaofsurfing.com; surfline.com",
  },

