  'greg-noll': {
    id: 'greg-noll',
    type: 'athlete',
    name: 'Greg Noll',
    nick: 'Da Bull',
    sport: ['surf'],
    location: 'Hermosa Beach, CA',
    era: '1950s–1960s',
    role: 'Big Wave Pioneer / Shaper / Filmmaker',
    bio: "Greg 'Da Bull' Noll is one of the most legendary figures in surfing history. Born in 1937, he grew up in Hermosa Beach and became one of the dominant big-wave surfers of the 1950s and 1960s — known for charging massive Waimea Bay when most surfers wouldn't dare. He famously rode what many considered the biggest wave ever surfed at the time at Makaha in 1969, during a historic swell that closed out most of the North Shore. He was also a pioneering shaper and surfboard manufacturer (Greg Noll Surfboards), and directed the film A Cool Wave of Color (1964). He is a Hall of Fame inductee and foundational figure of surf culture.",
    connections: [
      { id: 'a-cool-wave-of-color', label: 'Director (1964)' },
      { id: 'pipeline', label: 'Early big-wave pioneer' },
    ],
    source: "encyclopediaofsurfing.com; surfline.com",
  },

