  // === SURF COMPANIES — NEW ADDITIONS (Surfing_Companies_History-2.xlsx) ===
'velzy-surfboards': {
    id: 'velzy-surfboards',
    type: 'brand',
    name: "Velzy Surfboards",
    sport: ['surf'],
    founded: '1949',
    location: 'Manhattan Beach, CA',
    founders: "Dale Velzy",
    bio: "Widely regarded as the world's first commercial surf shop, founded by Dale Velzy in Manhattan Beach in 1949. Velzy was the first to put a brand name on a board, sponsor a surfer, print a surf T-shirt, and advertise commercially. He invented the Pig design in 1955. Riders included Miki Dora, Donald Takayama, and Mickey Munoz. The IRS closed his shops in 1959. Velzy died May 26, 2005.",
  },
  'gordon-woods-surfboards': {
    id: 'gordon-woods-surfboards',
    type: 'brand',
    name: "Gordon Woods Surfboards",
    sport: ['surf'],
    founded: '1946',
    location: 'Sydney, NSW, Australia',
    founders: "Gordon Woods",
    bio: "Gordon Woods opened one of the first commercial surfboard operations in Australia in 1946, introducing modern Californian surfboard designs to the country. His work helped trigger the surfing craze sparked by the 1956 Melbourne Olympics surfing demonstration by visiting Californians. Now defunct.",
  },
  'dave-sweet-surfboards': {
    id: 'dave-sweet-surfboards',
    type: 'brand',
    name: "Dave Sweet Surfboards",
    sport: ['surf'],
    founded: '1949',
    location: 'Santa Monica, CA',
    founders: "Dave Sweet",
    bio: "Dave Sweet pioneered the polyurethane foam blank revolution, producing the first commercial foam blanks in 1956 with funding from actor Cliff Robertson. His work directly replaced balsa construction and led to the modern fiberglass surfboard industry. Based in Santa Monica. Now defunct.",
  },
  'con-surfboards': {
    id: 'con-surfboards',
    type: 'brand',
    name: "Con Surfboards",
    sport: ['surf'],
    founded: '1959',
    location: 'Santa Monica, CA',
    founders: "Con Colburn",
    bio: "Con Surfboards was founded by Con Colburn on Pico Blvd in Santa Monica in 1959. The brand's Ugly noserider design became one of the most popular California longboard shapes of the 1960s. Now defunct.",
  },
  'yater-surfboards': {
    id: 'yater-surfboards',
    type: 'brand',
    name: "Yater Surfboards",
    sport: ['surf'],
    founded: '1959',
    location: 'Santa Barbara, CA',
    founders: "Reynolds 'Renny' Yater",
    bio: "Founded by Renny Yater in Santa Barbara, Yater Surfboards became synonymous with refined longboard craftsmanship. The Spoon model is considered a classic design still sought after today. Yater is widely regarded as one of the finest longboard shapers in history and remained active as a craftsman for over 60 years.",
  },
  'sundek': {
    id: 'sundek',
    type: 'brand',
    name: "Sundek",
    sport: ['surf'],
    founded: '1957',
    location: 'California / Italy',
    founders: "Various",
    bio: "Sundek was one of the first surf-specific boardshort brands, known for vibrant rainbow designs that became iconic in the 1960s through 1980s. Had strong runs through multiple decades and has been periodically revived. Now active as a niche premium Italian boardshort brand.",
  },
  'sticky-bumps': {
    id: 'sticky-bumps',
    type: 'brand',
    name: "Sticky Bumps",
    sport: ['surf'],
    founded: '1971',
    location: 'San Diego, CA',
    founders: "Wax Research",
    bio: "Sticky Bumps pioneered the two-coat surf wax system — basecoat plus topcoat — which is now standard practice globally. A direct competitor to Mr. Zog's Sex Wax, Sticky Bumps holds major market share in surf wax worldwide. Founded in San Diego in 1971.",
  },
  'florence-marine-x': {
    id: 'florence-marine-x',
    type: 'brand',
    name: "Florence Marine X",
    sport: ['surf'],
    founded: '2019',
    location: 'North Shore, HI',
    founders: "John John Florence, Nathan Florence",
    bio: "Florence Marine X was founded in 2019 by 3x WSL World Champion John John Florence and his brother Nathan Florence. The brand produces performance wetsuits using Yamamoto neoprene and sustainable apparel. It quickly gained credibility in both the North Shore and global surf communities.",
  },
  'morey-boogie': {
    id: 'morey-boogie',
    type: 'brand',
    name: "Morey Boogie",
    sport: ['surf'],
    founded: '1971',
    location: 'Carlsbad, CA',
    founders: "Tom Morey",
    bio: "Tom Morey invented the bodyboard in 1971 using a sheet of polyethylene foam and a newspaper template on a Hawaiian beach. The Boogie Board became one of the most popular ocean recreation products in history, opening wave riding to millions. The original Morey Boogie brand was later separated from the Morey name and passed through various ownership.",
  },
  'us-blanks': {
    id: 'us-blanks',
    type: 'brand',
    name: "US Blanks",
    sport: ['surf'],
    founded: '2006',
    location: 'Oceanside, CA',
    founders: "John Dowd",
    bio: "US Blanks was launched almost immediately after Clark Foam's sudden closure in December 2005 to fill the catastrophic supply vacuum left in the surfboard blank market. Founded by John Dowd in Oceanside, California, it became the dominant US supplier of polyurethane foam blanks for surfboard shapers.",
  },
  'catch-surf': {
    id: 'catch-surf',
    type: 'brand',
    name: "Catch Surf",
    sport: ['surf'],
    founded: '2007',
    location: 'San Clemente, CA',
    founders: "Dave Bier",
    bio: "Founded by Dave Bier in San Clemente in 2007, Catch Surf brought soft-top foam surfboards into the mainstream with the Odysea and Beater models. The brand ignited the modern soft-top craze, making surfing accessible to all skill levels and popularizing high-performance riding on foam boards.",
  },
  'globe-international': {
    id: 'globe-international',
    type: 'brand',
    name: "Globe International",
    sport: ['surf'],
    founded: '1994',
    location: 'Melbourne, Australia',
    founders: "Matthew Hill, Andrew Hill, Stephen Hill",
    bio: "Globe International was founded by the three Hill brothers — Matthew, Andrew, and Stephen — out of a garage skateboard operation in Melbourne in 1994. The company grew into a global surf and skate footwear and apparel company, producing Globe shoes, skateboard decks, and apparel brands including Salty Dog and Mada. Listed on the Australian Stock Exchange.",
  },


